phase1.code:
using UnityEngine;

public class BuildSettings : MonoBehaviour
{
    [Header("Build Info")]
    public string gameName = "My Game";
    public string version = "1.0.0";
    public string companyName = "Your Studio";
    public string buildDate = "";

    void Start()
    {
        buildDate = System.DateTime.Now.ToString("yyyy-MM-dd");

        Debug.Log("=== Build Settings ===");
        Debug.Log("Game: " + gameName);
        Debug.Log("Version: " + version);
        Debug.Log("Company: " + companyName);
        Debug.Log("Build Date: " + buildDate);

        Debug.Log("\n--- Build Targets ---");
        Debug.Log("1. PC (Windows, Mac, Linux)");
        Debug.Log("2. WebGL");
        Debug.Log("3. Android");
        Debug.Log("4. iOS");

        Debug.Log("\n--- Build Steps ---");
        Debug.Log("1. File → Build Settings");
        Debug.Log("2. Select target platform");
        Debug.Log("3. Click Build");
        Debug.Log("4. Choose output folder");
        Debug.Log("5. Wait for build to complete");
    }

    public void ShowBuildInfo()
    {
        Debug.Log("Game: " + gameName + " v" + version);
        Debug.Log("Built on: " + buildDate);
        Debug.Log("Built by: " + companyName);
    }
}

